    21	/**
    22	 * Helper to create document associations in the junction table
    23	 * This replaces the legacy program_id, project_id, sprint_id columns
    24	 */
    25	async function createAssociation(
    26	  pool: pg.Pool,
    27	  documentId: string,
    28	  relatedId: string,
    29	  relationshipType: 'program' | 'project' | 'sprint',
    30	  metadata?: Record<string, unknown>
    31	): Promise<void> {
    32	  await pool.query(
    33	    `INSERT INTO document_associations (document_id, related_id, relationship_type, metadata)
    34	     VALUES ($1, $2, $3, $4)
    35	     ON CONFLICT (document_id, related_id, relationship_type) DO NOTHING`,
    36	    [documentId, relatedId, relationshipType, JSON.stringify(metadata || { created_via: 'seed' })]
    37	  );
    38	}
    39	
    40	async function seed() {
    41	  // Load secrets from SSM in production (must happen before Pool creation)
    42	  await loadProductionSecrets();
    43	
    44	  const pool = new Pool({
    45	    connectionString: process.env.DATABASE_URL,
    46	    ssl: getDatabaseSslConfig(),
    47	  });
    48	  console.log('🌱 Starting database seed...');
    49	  // Only log hostname, never full connection string (contains credentials)
    50	  const dbHost = process.env.DATABASE_URL ? new URL(process.env.DATABASE_URL).hostname : 'unknown';
    51	  console.log(`   Database host: ${dbHost}`);
    52	
    53	  try {
    54	    const appliedNow = await ensureDatabaseSchema(pool, console);
    55	    console.log(
    56	      appliedNow.length === 0
    57	        ? '✅ Schema ready'
    58	        : `✅ Schema ready with ${appliedNow.length} pending migration(s) applied`,
    59	    );
    60	
    61	    // Check if workspace exists
    62	    const existingWorkspace = await pool.query(
    63	      'SELECT id FROM workspaces WHERE name = $1',
    64	      ['Ship Workspace']
    65	    );
    66	
    67	    let workspaceId: string;
    68	
    69	    if (existingWorkspace.rows[0]) {
    70	      workspaceId = existingWorkspace.rows[0].id;
    71	      console.log('ℹ️  Workspace already exists');
    72	    } else {
    73	      // Create workspace with sprint_start_date ~3 months ago, aligned to Monday.
    74	      // Weeks must start on Monday to match production and ensure the heatmap
    75	      // shows correct "due" (yellow) windows for plans (Sat-Mon) and retros (Thu-Fri).
    76	      const threeMonthsAgo = new Date();
    77	      threeMonthsAgo.setMonth(threeMonthsAgo.getMonth() - 3);
    78	      // Roll back to the nearest Monday (day 1)
    79	      const dayOfWeek = threeMonthsAgo.getDay(); // 0=Sun, 1=Mon, ...
    80	      const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
    81	      threeMonthsAgo.setDate(threeMonthsAgo.getDate() - daysToSubtract);
