    86	        ['Ship Workspace', threeMonthsAgo.toISOString().split('T')[0]]
    87	      );
    88	      workspaceId = workspaceResult.rows[0].id;
    89	      console.log('✅ Workspace created');
    90	    }
    91	
    92	    // Team members to seed (dev user + 10 fake users)
    93	    const teamMembers = [
    94	      { email: 'dev@ship.local', name: 'Dev User' },
    95	      { email: 'alice.chen@ship.local', name: 'Alice Chen' },
    96	      { email: 'bob.martinez@ship.local', name: 'Bob Martinez' },
    97	      { email: 'carol.williams@ship.local', name: 'Carol Williams' },
    98	      { email: 'david.kim@ship.local', name: 'David Kim' },
    99	      { email: 'emma.johnson@ship.local', name: 'Emma Johnson' },
   100	      { email: 'frank.garcia@ship.local', name: 'Frank Garcia' },
   101	      { email: 'grace.lee@ship.local', name: 'Grace Lee' },
   102	      { email: 'henry.patel@ship.local', name: 'Henry Patel' },
   103	      { email: 'iris.nguyen@ship.local', name: 'Iris Nguyen' },
   104	      { email: 'jack.brown@ship.local', name: 'Jack Brown' },
   105	    ];
   106	
   107	    const passwordHash = await bcrypt.hash('admin123', 10);
   108	    let usersCreated = 0;
   109	
   110	    for (const member of teamMembers) {
   111	      const existingUser = await pool.query(
   112	        'SELECT id FROM users WHERE LOWER(email) = LOWER($1)',
   113	        [member.email]
   114	      );
   115	
   116	      if (!existingUser.rows[0]) {
   117	        await pool.query(
   118	          `INSERT INTO users (email, password_hash, name, last_workspace_id)
   119	           VALUES ($1, $2, $3, $4)`,
   120	          [member.email, passwordHash, member.name, workspaceId]
   121	        );
   122	        usersCreated++;
   123	      }
   124	    }
   125	
   126	    if (usersCreated > 0) {
   127	      console.log(`✅ Created ${usersCreated} users (all use password: admin123)`);
   128	    } else {
   129	      console.log('ℹ️  All users already exist');
   130	    }
   131	
   132	    // Set dev user as super-admin and set their last workspace
   133	    await pool.query(
   134	      `UPDATE users SET is_super_admin = true, last_workspace_id = $1 WHERE email = 'dev@ship.local'`,
   135	      [workspaceId]
   136	    );
   137	    console.log('✅ Set dev@ship.local as super-admin');
   138	
   139	    // Create FleetGraph API token for dev user (matches FLEETGRAPH_API_TOKEN in .env.local)
   140	    const fleetgraphToken = process.env.FLEETGRAPH_API_TOKEN;
