   147	        const tokenPrefix = fleetgraphToken.slice(0, 12);
   148	        await pool.query(
   149	          `INSERT INTO api_tokens (user_id, workspace_id, name, token_hash, token_prefix)
   150	           VALUES ($1, $2, $3, $4, $5)
   151	           ON CONFLICT (user_id, workspace_id, name) DO UPDATE SET token_hash = $4, token_prefix = $5`,
   152	          [devUser.rows[0].id, workspaceId, 'FleetGraph Agent', tokenHash, tokenPrefix]
   153	        );
   154	        console.log('✅ FleetGraph API token seeded');
   155	      }
   156	    } else {
   157	      console.log('ℹ️  FLEETGRAPH_API_TOKEN not set, skipping API token seed');
   158	    }
   159	
   160	    // Create workspace memberships and Person documents for all users
   161	    // Note: These are independent - no coupling via person_document_id
   162	    let membershipsCreated = 0;
   163	    let personDocsCreated = 0;
   164	    const allUsersForMembership = await pool.query(
