    10	const migrationsDir = join(__dirname, 'migrations');
    11	
    12	export type BootstrapLogger = Pick<Console, 'log' | 'error'>;
    13	export type MigrationPool = Pick<pg.Pool, 'query' | 'connect'>;
    14	
    15	async function hasExistingSchema(pool: Pick<pg.Pool, 'query'>): Promise<boolean> {
    16	  const result = await pool.query(`SELECT to_regclass('public.workspaces') IS NOT NULL AS has_schema`);
    17	  return result.rows[0]?.has_schema === true;
    18	}
    19	
    20	function isIgnorableSchemaError(error: unknown): boolean {
    21	  if (!(error instanceof Error) || !('code' in error)) return false;
    22	  if ((error as { code?: string; detail?: string }).code === '23505') {
    23	    const detail = (error as { detail?: string }).detail ?? '';
    24	    return detail.includes('(extname)=(pg_trgm)');
    25	  }
    26	  return error.message.includes('already exists');
    27	}
    28	
    29	export async function ensureDatabaseSchema(pool: MigrationPool, logger?: BootstrapLogger): Promise<string[]> {
    30	  if (!(await hasExistingSchema(pool))) {
    31	    const schema = readFileSync(schemaPath, 'utf-8');
    32	    try {
    33	      await pool.query(schema);
    34	    } catch (error) {
    35	      if (!isIgnorableSchemaError(error)) throw error;
    36	      logger?.log('Schema already present, continuing with pending migrations');
    37	    }
    38	  }
    39	
    40	  await pool.query(`CREATE TABLE IF NOT EXISTS schema_migrations (version TEXT PRIMARY KEY, applied_at TIMESTAMPTZ DEFAULT now())`);
    41	  const appliedResult = await pool.query('SELECT version FROM schema_migrations ORDER BY version');
    42	  const appliedMigrations = new Set(appliedResult.rows.map((row) => row.version as string));
    43	  const migrationFiles = existsSync(migrationsDir) ? readdirSync(migrationsDir).filter((file) => file.endsWith('.sql')).sort() : [];
    44	  const appliedNow: string[] = [];
    45	
    46	  for (const file of migrationFiles) {
    47	    const version = file.replace(/\.sql$/, '');
    48	    if (appliedMigrations.has(version)) continue;
    49	    const client = await pool.connect();
    50	    try {
    51	      await client.query('BEGIN');
    52	      await client.query(readFileSync(join(migrationsDir, file), 'utf-8'));
    53	      await client.query('INSERT INTO schema_migrations (version) VALUES ($1)', [version]);
    54	      await client.query('COMMIT');
    55	      appliedNow.push(version);
    56	      logger?.log(`Applied migration ${version}`);
    57	    } catch (error) {
    58	      await client.query('ROLLBACK');
    59	      logger?.error(`Migration failed: ${version}`);
    60	      throw error;
    61	    } finally {
    62	      client.release();
    63	    }
    64	  }
    65	
    66	  return appliedNow;
    67	}
